    analytics_storage: 'granted'
  };

  var DENIED = {
    ad_storage: 'denied',
    ad_user_data: 'denied',
    ad_personalization: 'denied',
    analytics_storage: 'denied'
  };

  // Ensure dataLayer and gtag exist
