    ad_storage: 'denied',
    ad_user_data: 'denied',
    ad_personalization: 'denied',
    analytics_storage: 'denied',
    wait_for_update: 500
  });

  // DNT check — if enabled, stay denied and never show banner
  if (navigator.doNotTrack === '1' || window.doNotTrack === '1') {
    return;
